  //Check if identity is active, else false
  //Check if the identity.jobcode is not null and matches one of the jobcodes in custom object, if no match return false
  //Check if the DC of the nativeIdentity matches any of the DCs IT Roles 

  import sailpoint.tools.Util;
  import java.util.ArrayList;
  import java.util.List;
  import sailpoint.object.Bundle;
  import sailpoint.object.Custom;

  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  boolean jobCodeFlag=false;
  boolean dnMatched=false;

  String identityJobCode = identity.getAttribute("jobcode");
  if(null==identityJobCode){
    return false;
  }
  if(identity.isInactive()){
    return false;
  }
  Custom custom = context.getObjectByName(Custom.class, "Acension-Custom-OneNurse-JobCode");
  List codeList = (List)custom.get("CodeList");
  for(String jcode : codeList){
    if(identityJobCode.equalsIgnoreCase(jcode) ){
      jobCodeFlag=true;
      break;
    }
  }

  List idLinksDN = getIdLinksDN(identity);
  String itRoleName = roleName+"-IT";
  Bundle bundle = context.getObjectByName(Bundle.class, itRoleName);
  if(bundle != null @and idLinksDN.size()>0){
    List bundleValues = getBundleEntitlements(bundle);
    //log.trace("Condition bundleValues ****"+bundleValues);
    for(String idLinkDN : idLinksDN){
      dnMatched = containsIgnoreCase(bundleValues,idLinkDN);
    }
  }
  if(dnMatched @and jobCodeFlag){
    return true;           
  }

  return false;
